import React from 'react';
import { Button, Modal } from '@linm-soft-org/linm-web-common-components';
import styles from './ConfirmSaveVoucherModal.module.css';

export interface ConfirmSaveField {
  /** Label text displayed above the value. */
  label: string;
  /** Content shown below the label (string, formatted number, ReactNode). */
  value: React.ReactNode;
  /** Full data-testid value (already prefixed by caller). */
  testId: string;
  /** If true, field spans the full width (2 columns). */
  fullWidth?: boolean;
  /** If true, field is not rendered. */
  hidden?: boolean;
}

export interface ConfirmSaveVoucherModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  saving?: boolean;
  /** Modal title — default "Xác nhận lưu chứng từ". */
  title?: string;
  /** Ordered array of fields to display in 2-column grid. */
  fields: ConfirmSaveField[];
  /** Prefix for test IDs on action buttons. */
  testIdPrefix: string;
}

export const ConfirmSaveVoucherModal: React.FC<ConfirmSaveVoucherModalProps> = ({
  isOpen,
  onClose,
  onConfirm,
  saving,
  title = 'Xác nhận lưu chứng từ',
  fields,
  testIdPrefix,
}) => {
  const tid = (suffix: string) => `${testIdPrefix}-confirm-save-${suffix}`;

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} closeOnOverlayClick={false}>
      <div className={styles.fields}>
        {fields.map((field, index) =>
          field.hidden ? null : (
            <div
              key={index}
              className={`${styles.field}${field.fullWidth ? ` ${styles.fullWidth}` : ''}`}
            >
              <span className={styles.label}>{field.label}</span>
              <span className={styles.value} data-testid={field.testId}>
                {field.value}
              </span>
            </div>
          ),
        )}
      </div>
      <div className={styles.actions}>
        <Button variant="secondary" onClick={onClose} data-testid={tid('cancel')}>
          Hủy
        </Button>
        <Button variant="primary" onClick={onConfirm} loading={saving} data-testid={tid('confirm')}>
          Xác nhận
        </Button>
      </div>
    </Modal>
  );
};
