import React, { useEffect, useState } from 'react';
import { Button, Modal, Select } from '@linm-soft-org/linm-web-common-components';
import type { SelectOption } from '@linm-soft-org/linm-web-common-components';
import styles from '../../styles/documentForm.module.css';

export interface ProcessingLevelApproveModalProps {
  isOpen: boolean;
  onClose: () => void;
  currentLevel: string;
  levelOptions: SelectOption[];
  onConfirm: (newLevel: string) => void | Promise<void>;
  saving?: boolean;
  testIdPrefix: string;
  /** List batch — nhiều phiếu mức khác nhau; Xác nhận luôn enable khi đã chọn mức. */
  batchMode?: boolean;
  /** Batch — số phiếu đã chọn (hiển thị gợi ý thay «mức hiện tại»). */
  selectedCount?: number;
}

/**
 * Phê duyệt — chọn mức xử lý mới (persist qua PUT khi chứng từ đã lưu).
 */
export const ProcessingLevelApproveModal: React.FC<ProcessingLevelApproveModalProps> = ({
  isOpen,
  onClose,
  currentLevel,
  levelOptions,
  onConfirm,
  saving = false,
  testIdPrefix,
  batchMode = false,
  selectedCount = 0,
}) => {
  const [selected, setSelected] = useState(currentLevel);

  useEffect(() => {
    if (!isOpen) return;
    if (batchMode) {
      setSelected(levelOptions[0]?.value?.toString() ?? currentLevel);
      return;
    }
    setSelected(currentLevel);
  }, [isOpen, currentLevel, batchMode, levelOptions]);

  const currentLabel = levelOptions.find(o => o.value === currentLevel)?.label ?? currentLevel;
  const confirmDisabled = batchMode ? !selected : !selected || selected === currentLevel;

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Phê duyệt — Mức xử lý"
      size="sm"
      data-testid={`${testIdPrefix}-approve-modal`}
    >
      {batchMode ? (
        <p style={{ marginBottom: 12, color: 'var(--color-text-secondary, #6b7280)', fontSize: 14 }}>
          Áp dụng mức xử lý cho{' '}
          <strong>{selectedCount > 0 ? `${selectedCount} phiếu đã chọn` : 'các phiếu đã chọn'}</strong>
          . Mỗi phiếu chỉ đổi mức khi đủ điều kiện nghiệp vụ.
        </p>
      ) : (
        <p style={{ marginBottom: 12, color: 'var(--color-text-secondary, #6b7280)', fontSize: 14 }}>
          Mức xử lý hiện tại: <strong>{currentLabel}</strong>
        </p>
      )}
      <div style={{ marginBottom: 16 }}>
        <label className={styles.label} htmlFor={`${testIdPrefix}-approve-level`}>
          Chuyển sang mức xử lý
        </label>
        <Select
          id={`${testIdPrefix}-approve-level`}
          data-testid={`${testIdPrefix}-approve-level`}
          options={levelOptions}
          value={selected}
          onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setSelected(e.target.value)}
        />
      </div>
      <div className={styles.modalActions}>
        <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-approve-cancel`}>
          Hủy
        </Button>
        <Button
          variant="primary"
          onClick={() => onConfirm(selected)}
          loading={saving}
          disabled={confirmDisabled}
          data-testid={`${testIdPrefix}-approve-confirm`}
        >
          <i className="fas fa-check" /> Xác nhận
        </Button>
      </div>
    </Modal>
  );
};
