/**
 * Voucher header compact helpers — `web-app/rule/voucher-header-compact.md`
 * Thu gọn chỉ ẩn field; grid `.row4` không đổi (CSS `documentForm.module.css`).
 */
export type VoucherHeaderCompactStyles = {
  field: string;
  headerCompactHidden: string;
  headerCompactActive: string;
};

export function useVoucherHeaderCompact(options: {
  enabled: boolean;
  headerExpanded: boolean;
  styles: VoucherHeaderCompactStyles;
}) {
  const { enabled, headerExpanded, styles } = options;
  const isCompact = enabled && !headerExpanded;

  const compactHideClass = (visibleWhenCompact: boolean) =>
    isCompact && !visibleWhenCompact ? styles.headerCompactHidden : undefined;

  const headerCompactSectionClass = isCompact ? styles.headerCompactActive : undefined;

  const fieldClass = (...parts: (string | false | undefined)[]) =>
    [styles.field, ...parts].filter(Boolean).join(' ');

  return {
    isCompact,
    compactHideClass,
    headerCompactSectionClass,
    fieldClass,
  };
}
