import React from 'react';
import { Input, Select, type SelectOption } from '@linm-soft-org/linm-web-common-components';
import df from '../../styles/documentForm.module.css';

export type CurrencyPairFieldProps = {
  currencyCode: string;
  exchangeRate: string | number;
  currencyOptions: SelectOption[];
  staticFieldProps: React.ComponentProps<typeof Input>;
  selectDisabled?: boolean;
  currencyLabel?: string;
  exchangeRateLabel?: string;
  testId: (suffix: string) => string;
  className?: string;
  /** NT:TG flex trong ô — default `6-4` (`currency-field.md`); PT/PC header 5 cột: `4-2`. */
  pairRatio?: '6-4' | '4-2';
};

/** NT + TG readonly pair — 1 ô grid; flex 6:4 (default) hoặc 4:2. */
export const CurrencyPairField: React.FC<CurrencyPairFieldProps> = ({
  currencyCode,
  exchangeRate,
  currencyOptions,
  staticFieldProps,
  selectDisabled = false,
  currencyLabel = 'Ngoại tệ',
  exchangeRateLabel = 'Tỷ giá',
  testId,
  className,
  pairRatio = '6-4',
}) => {
  const ratioClass = pairRatio === '4-2' ? df.currencyPairRatio42 : '';
  return (
  <div className={className} data-testid={testId('field-currencyPair')}>
    <div className={[df.currencyPair, ratioClass].filter(Boolean).join(' ')}>
      <div className={df.currencyPairMain} data-testid={testId('field-currencyCode')}>
        <label className={df.label}>{currencyLabel}</label>
        <Select
          data-testid={testId('field-currencyCode-select')}
          options={currencyOptions}
          value={currencyCode}
          onChange={() => {}}
          disabled={selectDisabled || currencyOptions.length === 0}
        />
      </div>
      <div className={df.currencyPairRate} data-testid={testId('field-exchangeRate')}>
        <label className={df.label}>{exchangeRateLabel}</label>
        <Input type="number" value={exchangeRate} {...staticFieldProps} />
      </div>
    </div>
  </div>
  );
};
